const rows = $input.all();
const month_keys = rows.map(r => r.json.month_key).filter(Boolean);

if (month_keys.length === 0) {
  return [
    {
      json: {
        skip: true,
        month_keys: [],
        steps: []
      }
    }
  ];
}

return [
  {
    json: {
      skip: false,
      month_keys: month_keys,
      steps: ["stage", "engine", "ml"]
    }
  }
];

const data = $json;

const runId = data.run_id || 'unknown';
const results = data.results || [];

let success = [];
let skipped = [];
let failed = [];

for (const r of results) {
  const pipelineStatus = r.pipeline?.status;
  const mlStatus = r.ml?.status;

  if (pipelineStatus === 'ok') {
    const mlNote = (mlStatus && mlStatus !== 'ok')
      ? ` (ML: ${mlStatus})`
      : '';
    success.push(`- ${r.month_key}${mlNote}`);
  }
  else if (pipelineStatus === 'skipped_guardrail') {
    skipped.push(`- ${r.month_key} (Guardrail hat Monat übersprungen, rc=42)`);
  }
  else {
    let reason = 'Unbekannter Fehler';
    const stderr = r.pipeline?.stderr || '';

    if (stderr.includes('Local file not found')) {
      reason = 'Quelldatei nicht gefunden';
    } else if (stderr.includes('detektor')) {
      reason = 'Dateiname-Mismatch (detektor vs detektoren)';
    } else if (stderr.includes('UniqueViolation')) {
      reason = 'UniqueViolation – --replace-month-slice fehlt?';
    } else if (pipelineStatus === 'error') {
      reason = 'Pipeline-Fehler (siehe Logs)';
    }

    failed.push(`- ${r.month_key}: ${reason}`);
  }
}

const successText = success.length ? success.join('\n') : '_keine_';
const skippedText = skipped.length ? skipped.join('\n') : '_keine_';
const failedText  = failed.length  ? failed.join('\n')  : '_keine_';

const overallStatus = failed.length > 0
  ? ':x: completed_with_errors'
  : ':white_check_mark: completed';

const message = `:package: *KPI Confidence Pipeline – Execution Report*

Run ID: ${runId}

────────────────────────

:white_check_mark: *Erfolgreich verarbeitet*
${successText}

:warning: *Übersprungen (Guardrail)*
${skippedText}

:x: *Fehlgeschlagen*
${failedText}

────────────────────────

:bar_chart: *Zusammenfassung*
Gesamt: ${results.length}  |  OK: ${success.length}  |  Guardrail: ${skipped.length}  |  Fehler: ${failed.length}

Status: ${overallStatus}`;

return [ { json: { text: message } } ];

return [
  {
    json: {
      text: ':information_source: *KPI Confidence Pipeline* – Workflow 2 gestartet, aber keine neu ingesierten Monate gefunden. Keine Pipeline-Ausführung notwendig.'
    }
  }
];
